mapper.insert:
INSERT INTO orders (
auction_idx, bid_idx, buyer_idx, seller_idx,
order_amount, order_status, is_settled
) VALUES (
#{auctionIdx}, #{bidIdx}, #{buyerIdx}, #{sellerIdx},
